/**
 * @fileoverview FloatingWindow DOM setup/teardown + visual feedback helpers.
 * @module module/FloatingWindow/view
 */

import razyui from '../../index.js';
import {
    CLS, SEL, RESIZE_DIRS, BTN_LABELS,
    SNAP_OVERLAY_HTML, ATTACH_GUIDE_HTML, PART,
} from './constants.js';
import { makeBtn, snapRect } from './helpers.js';

/**
 * Build the floating window DOM tree and append it to document.body.
 *
 * @param {object} config — window configuration
 * @param {string} id     — unique window ID
 * @param {{ x: number, y: number }} pos  — initial position
 * @param {{ w: number, h: number }} size — initial size
 * @returns {{ win: HTMLElement, header: HTMLElement, titleEl: HTMLElement,
 *             body: HTMLElement, overlay: HTMLElement|null, guide: HTMLElement|null,
 *             btnRefs: { min: HTMLElement|null, max: HTMLElement|null, close: HTMLElement|null } }}
 */
export function buildWindow(config, id, pos, size) {
    const w = PART.WINDOW.create({ id });
    w.addClass('floating-window');
    w.css({
        left: (config.x ?? pos.x) + 'px',
        top: (config.y ?? pos.y) + 'px',
        width: size.w + 'px',
        height: size.h + 'px',
    });

    // ── Header ──
    const header = PART.HEADER.create();

    const title = PART.TITLE.create({ textContent: config.title });
    header.append(title);

    const btns = PART.HEADER_BTNS.create();

    const btnRefs = { min: null, max: null, close: null };

    if (config.minimisable) {
        btnRefs.min = makeBtn(CLS.BTN_MIN, BTN_LABELS.MIN.html, BTN_LABELS.MIN.title);
        PART.BTN.apply(btnRefs.min);
        btns.append(btnRefs.min);
    }
    if (config.maximisable) {
        btnRefs.max = makeBtn(CLS.BTN_MAX, BTN_LABELS.MAX.html, BTN_LABELS.MAX.title);
        PART.BTN.apply(btnRefs.max);
        btns.append(btnRefs.max);
    }
    if (config.closable) {
        btnRefs.close = makeBtn(CLS.BTN_CLOSE, BTN_LABELS.CLOSE.html, BTN_LABELS.CLOSE.title);
        PART.BTN.apply(btnRefs.close);
        btns.append(btnRefs.close);
    }

    header.append(btns);

    // ── Body ──
    const body = PART.BODY.create();
    if (typeof config.content === 'string') {
        body.html(config.content);
    } else if (config.content instanceof HTMLElement) {
        body.append(config.content);
    }

    // ── Resize handles ──
    if (config.resizable) {
        for (const dir of RESIZE_DIRS) {
            const handle = PART.RESIZE.create({ 'data-dir': dir });
            handle.addClass('fw-resize-' + dir);
            w.append(handle);
        }
    }

    w.append(header)
     .append(body);

    // ── Snap overlay (appended to document.body) ──
    let overlay = null;
    if (config.snap) {
        overlay = PART.SNAP_OVERLAY.create({ innerHTML: SNAP_OVERLAY_HTML });
        PART.SNAP_PREVIEW.apply(overlay.find(SEL.SNAP_PREVIEW));
        razyui(document.body).append(overlay);
    }

    // ── Attach guide (appended to document.body) ──
    let guide = null;
    if (config.attachSnap) {
        guide = PART.ATTACH_GUIDE.create({ innerHTML: ATTACH_GUIDE_HTML });
        PART.ATTACH_LINE.apply(guide.find(SEL.ATTACH_LINE));
        razyui(document.body).append(guide);
    }

    razyui(document.body).append(w);

    return { win: w, header, titleEl: title, body, overlay, guide, btnRefs };
}

// ── Snap preview ─────────────────────────────────────────

/**
 * Show the snap preview overlay at the given zone.
 * @param {HTMLElement|null} overlay
 * @param {string} zone
 */
export function showSnapPreview(overlay, zone) {
    if (!overlay) return;
    const preview = overlay.find(SEL.SNAP_PREVIEW);
    overlay.css('display', '');
    const r = snapRect(zone);
    preview.css({ left: r.x + 'px', top: r.y + 'px', width: r.w + 'px', height: r.h + 'px' });
}

/**
 * Hide the snap preview overlay.
 * @param {HTMLElement|null} overlay
 */
export function hideSnapPreview(overlay) {
    if (overlay) overlay.css('display', 'none');
}

// ── Attach guide ─────────────────────────────────────────

/**
 * Draw the attach guide line at the specified edge.
 * @param {HTMLElement|null} guide
 * @param {object} edge — attach edge info from findAttachEdge
 */
export function showAttachGuide(guide, edge) {
    if (!guide) return;
    guide.css('display', '');
    const line = guide.find(SEL.ATTACH_LINE);

    switch (edge.side) {
        case 'right':
            line.css({
                left: edge.them.left + 'px',
                top: Math.min(edge.me.top, edge.them.top) + 'px',
                width: '2px',
                height: (Math.max(edge.me.bottom, edge.them.bottom) - Math.min(edge.me.top, edge.them.top)) + 'px',
            });
            break;
        case 'left':
            line.css({
                left: edge.them.right + 'px',
                top: Math.min(edge.me.top, edge.them.top) + 'px',
                width: '2px',
                height: (Math.max(edge.me.bottom, edge.them.bottom) - Math.min(edge.me.top, edge.them.top)) + 'px',
            });
            break;
        case 'bottom':
            line.css({
                left: Math.min(edge.me.left, edge.them.left) + 'px',
                top: edge.them.top + 'px',
                width: (Math.max(edge.me.right, edge.them.right) - Math.min(edge.me.left, edge.them.left)) + 'px',
                height: '2px',
            });
            break;
        case 'top':
            line.css({
                left: Math.min(edge.me.left, edge.them.left) + 'px',
                top: edge.them.bottom + 'px',
                width: (Math.max(edge.me.right, edge.them.right) - Math.min(edge.me.left, edge.them.left)) + 'px',
                height: '2px',
            });
            break;
    }
}

/**
 * Hide the attach guide.
 * @param {HTMLElement|null} guide
 */
export function hideAttachGuide(guide) {
    if (guide) guide.css('display', 'none');
}

// ── Cleanup ──────────────────────────────────────────────

/**
 * Remove all window DOM elements during close.
 * @param {Elements|null} win
 * @param {Elements|null} overlay
 * @param {Elements|null} guide
 */
export function cleanupDOM(win, overlay, guide) {
    overlay?.[0].remove();
    guide?.[0].remove();
    win?.[0].remove();
}
