/**
 * @fileoverview FloatingWindow centralised event binding with AbortController.
 * @module module/FloatingWindow/events
 */

import razyui from '../../index.js';
import { CLS, SEL, DEFAULTS } from './constants.js';

/**
 * Bind drag events on the header bar (mouse, touch, dblclick).
 *
 * @param {HTMLElement} header — the .fw-header element
 * @param {object} ctx — drag context callbacks
 * @param {Function} ctx.getWin            — returns the .fw-window element
 * @param {Function} ctx.getPos            — returns { x, y }
 * @param {Function} ctx.setPos            — (x, y) => void
 * @param {Function} ctx.applyPosition     — (x, y) => void  (updates DOM)
 * @param {Function} ctx.getSnapZone       — returns current snap zone or null
 * @param {Function} ctx.isSnapEnabled     — returns boolean
 * @param {Function} ctx.isAttachSnapEnabled — returns boolean
 * @param {Function} ctx.detectEdgeSnap    — (cx, cy) => zone|null
 * @param {Function} ctx.detectAttachSnap  — () => edge|null
 * @param {Function} ctx.showSnapPreview   — (zone) => void
 * @param {Function} ctx.hideSnapPreview   — () => void
 * @param {Function} ctx.showAttachGuide   — (edge) => void
 * @param {Function} ctx.hideAttachGuide   — () => void
 * @param {Function} ctx.unsnap            — (cx, cy) => void
 * @param {Function} ctx.snapTo            — (zone) => void
 * @param {Function} ctx.applyAttach       — (edge) => void
 * @param {Function} ctx.saveState         — () => void
 * @param {Function} ctx.onMove            — () => void  (fire config callback)
 * @param {AbortSignal} signal             — for cleanup
 */
export function bindDragEvents(header, ctx, signal) {
    let startX, startY, startLeft, startTop;
    let dragZone = null;
    let attachEdge = null;
    let wasDragged = false;

    const onMove = (e) => {
        const cx = e.touches ? e.touches[0].clientX : e.clientX;
        const cy = e.touches ? e.touches[0].clientY : e.clientY;

        // Unsnap on first move if currently snapped
        if (ctx.getSnapZone() && !wasDragged) {
            ctx.unsnap(cx, cy);
            startX = cx; startY = cy;
            startLeft = ctx.getPos().x; startTop = ctx.getPos().y;
        }
        wasDragged = true;

        // Move
        const x = cx - startX + startLeft;
        const y = cy - startY + startTop;
        const clampedX = Math.max(0, Math.min(window.innerWidth - DEFAULTS.edgeLimit, x));
        const clampedY = Math.max(0, Math.min(window.innerHeight - DEFAULTS.edgeLimit, y));
        ctx.setPos(clampedX, clampedY);
        ctx.applyPosition(clampedX, clampedY);

        // Detect snap zones
        dragZone = null;
        attachEdge = null;

        if (ctx.isSnapEnabled()) {
            dragZone = ctx.detectEdgeSnap(cx, cy);
        }
        if (dragZone) {
            ctx.showSnapPreview(dragZone);
            ctx.hideAttachGuide();
        } else if (ctx.isAttachSnapEnabled()) {
            attachEdge = ctx.detectAttachSnap();
            if (attachEdge) {
                ctx.showAttachGuide(attachEdge);
                ctx.previewAttach(attachEdge);
            }
            else ctx.hideAttachGuide();
            ctx.hideSnapPreview();
        } else {
            ctx.hideSnapPreview();
            ctx.hideAttachGuide();
        }

        ctx.onMove?.();
    };

    const onUp = () => {
        ctx.getWin().removeClass(CLS.DRAGGING);
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
        document.removeEventListener('touchmove', onMove);
        document.removeEventListener('touchend', onUp);
        ctx.hideSnapPreview();
        ctx.hideAttachGuide();

        if (dragZone) {
            ctx.snapTo(dragZone);
        } else if (attachEdge) {
            ctx.applyAttach(attachEdge);
        } else {
            ctx.saveState();
        }
        dragZone = null;
        attachEdge = null;
        wasDragged = false;
    };

    const $header = razyui(header);

    // Mouse drag
    $header.on('mousedown', (e) => {
        if (e.target.closest(SEL.BTN)) return;
        e.preventDefault();
        ctx.getWin().addClass(CLS.DRAGGING);
        wasDragged = false;
        startX = e.clientX; startY = e.clientY;
        startLeft = ctx.getWin()[0].offsetLeft; startTop = ctx.getWin()[0].offsetTop;
        document.addEventListener('mousemove', onMove, { signal });
        document.addEventListener('mouseup', onUp, { signal });
    }, { signal });

    // Touch drag
    $header.on('touchstart', (e) => {
        if (e.target.closest(SEL.BTN)) return;
        e.preventDefault();
        ctx.getWin().addClass(CLS.DRAGGING);
        wasDragged = false;
        const t = e.touches[0];
        startX = t.clientX; startY = t.clientY;
        startLeft = ctx.getWin()[0].offsetLeft; startTop = ctx.getWin()[0].offsetTop;
        document.addEventListener('touchmove', onMove, { passive: false, signal });
        document.addEventListener('touchend', onUp, { signal });
    }, { signal, passive: false });

    // Double-click → toggle full-screen
    $header.on('dblclick', (e) => {
        if (e.target.closest(SEL.BTN)) return;
        if (ctx.getSnapZone()) ctx.unsnap(window.innerWidth / 2, window.innerHeight / 2);
        else ctx.snapTo('full');
    }, { signal });
}

/**
 * Bind resize events on the 8 resize handles.
 *
 * @param {HTMLElement} win  — the .fw-window element
 * @param {object} ctx      — resize context callbacks
 * @param {Function} ctx.setPos   — (x, y) => void
 * @param {Function} ctx.setSize  — (w, h) => void
 * @param {Function} ctx.saveState — () => void
 * @param {Function} [ctx.onResize] — (w, h) => void
 * @param {AbortSignal} signal     — for cleanup
 */
export function bindResizeEvents(win, ctx, signal) {
    const handles = win.find(SEL.RESIZE);
    for (const handle of handles) {
        razyui(handle).on('mousedown', (e) => {
            e.preventDefault();
            e.stopPropagation();
            startResize(e, handle.dataset.dir, win, ctx, signal);
        }, { signal });
    }
}

/**
 * Begin a resize drag operation.
 * @param {MouseEvent} e
 * @param {string} dir   — resize direction (n, s, e, w, nw, ne, sw, se)
 * @param {HTMLElement} win
 * @param {object} ctx
 */
function startResize(e, dir, win, ctx, signal) {
    const startX = e.clientX, startY = e.clientY;
    const rect = win[0].getBoundingClientRect();
    const startW = rect.width, startH = rect.height;
    const startL = rect.left, startT = rect.top;
    const minW = DEFAULTS.minW, minH = DEFAULTS.minH;

    const onMove = (ev) => {
        const dx = ev.clientX - startX;
        const dy = ev.clientY - startY;
        let w = startW, h = startH, l = startL, t = startT;

        if (dir.includes('e')) w = Math.max(minW, startW + dx);
        if (dir.includes('w')) { w = Math.max(minW, startW - dx); l = startL + startW - w; }
        if (dir.includes('s')) h = Math.max(minH, startH + dy);
        if (dir.includes('n')) { h = Math.max(minH, startH - dy); t = startT + startH - h; }

        win.css({ width: w + 'px', height: h + 'px', left: l + 'px', top: t + 'px' });
        ctx.setPos(l, t);
        ctx.setSize(w, h);
        ctx.onResize?.(w, h);
    };

    const onUp = () => {
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
        ctx.saveState();
    };

    document.addEventListener('mousemove', onMove, { signal });
    document.addEventListener('mouseup', onUp, { signal });
}
