/**
 * @fileoverview FloatingWindow constants — CSS, class names, thresholds, defaults.
 * @module module/FloatingWindow/constants
 */

import { Z_DIALOG } from '../shared/tokens/z-index.js';
import { TRUNCATE, SCROLL_BODY, ICON_BTN_RESET } from '../shared/styleFragments.js';

// ── Instance registry (for snap-to-attach & z-indexing) ──
export const instances = new Set();
let _topZ = Z_DIALOG;

/** Increment and return the next z-index value. */
export function nextZ() { return ++_topZ; }

// ── Snap thresholds ──
/** Pixels from viewport edge to trigger edge-snap. */
export const SNAP_EDGE = 24;
/** Pixels proximity to trigger attach-snap to sibling. */
export const ATTACH_MAG = 14;
/** Gap between attached windows. */
export const ATTACH_GAP = 0;

// ── CSS class names ──
export const CLS = Object.freeze({
    WINDOW:            'fw-window',
    FOCUSED:           'fw-focused',
    DRAGGING:          'fw-dragging',
    SNAPPED:           'fw-snapped',
    MINIMISED:         'fw-minimised',
    HEADER:            'fw-header',
    title:             'fw-title',
    HEADER_BTNS:       'fw-header-btns',
    BTN:               'fw-btn',
    BTN_MIN:           'fw-btn fw-btn-min',
    BTN_MAX:           'fw-btn fw-btn-max',
    BTN_CLOSE:         'fw-btn fw-btn-close',
    BODY:              'fw-body',
    RESIZE:            'fw-resize',
    SNAP_OVERLAY:      'fw-snap-overlay',
    SNAP_PREVIEW:      'fw-snap-preview',
    ATTACH_GUIDE:      'fw-attach-guide',
    ATTACH_GUIDE_LINE: 'fw-attach-guide-line',
});

// ── Selectors ──
export const SEL = Object.freeze({
    SNAP_PREVIEW: '.fw-snap-preview',
    RESIZE:       '.fw-resize',
    ATTACH_LINE:  '.fw-attach-guide-line',
    BTN:          '.fw-btn',
});

// ── Resize handle directions ──
export const RESIZE_DIRS = Object.freeze(['n', 's', 'w', 'e', 'nw', 'ne', 'sw', 'se']);

