// ── Button labels ──
import Icons from '../Icons.js';
import { defineParts } from '../shared/definePart.js';
export const BTN_LABELS = Object.freeze({
    MIN:   { html: Icons.svg('minus',    { size: 10, strokeWidth: 2 }), title: 'Minimise' },
    MAX:   { html: Icons.svg('maximize', { size: 10, strokeWidth: 2 }), title: 'Maximise' },
    CLOSE: { html: Icons.svg('x',     { size: 10, strokeWidth: 2 }), title: 'Close' },
});

// ── Snap overlay / attach guide inner HTML ──
export const SNAP_OVERLAY_HTML = '<div class="fw-snap-preview"></div>';
export const ATTACH_GUIDE_HTML = '<div class="fw-attach-guide-line"></div>';

/** Semantic part names for JIT styling overrides. */
export const PART = defineParts('FloatingWindow', {
    WINDOW      : { class: 'fw-window', aliases: ['window', 'root', 'container'] },
    HEADER      : { class: 'fw-header', aliases: ['header'] },
    TITLE       : { class: 'fw-title', tag: 'span', aliases: ['title'] },
    HEADER_BTNS : { class: 'fw-header-btns', tag: 'span' },
    BTN         : { class: 'fw-btn', tag: 'button', aliases: ['btn', 'button'] },
    BODY        : { class: 'fw-body', aliases: ['body'] },
    RESIZE      : { class: 'fw-resize' },
    SNAP_OVERLAY: { class: 'fw-snap-overlay' },
    SNAP_PREVIEW: { class: 'fw-snap-preview' },
    ATTACH_GUIDE: { class: 'fw-attach-guide' },
    ATTACH_LINE : { class: 'fw-attach-guide-line' },
});

PART.WINDOW.jit   = 'fixed flex flex-col [min-width:var(--fw-min-width)] [min-height:var(--fw-min-height)] overflow-hidden select-none {fw-dragging}:[opacity:0.92] {fw-dragging}:[transition:none] {fw-snapped}:[transition:left_.3s_cubic-bezier(0.4,0,0.2,1),_top_.3s_cubic-bezier(0.4,0,0.2,1),_width_.3s_cubic-bezier(0.4,0,0.2,1),_height_.3s_cubic-bezier(0.4,0,0.2,1)] {fw-minimised}:[height:auto_!important] {fw-minimised}:[min-height:0]';
PART.HEADER.jit   = 'flex items-center shrink-0 [cursor:grab] ^{fw-dragging}:[cursor:grabbing]';
PART.TITLE.jit    = TRUNCATE + ' [pointer-events:none]';
PART.HEADER_BTNS.jit = 'flex items-center shrink-0';
PART.BTN.jit      = ICON_BTN_RESET;
PART.BODY.jit     = SCROLL_BODY + ' [user-select:text] ^{fw-minimised}:hidden';
PART.RESIZE.jit   = 'absolute [z-index:1] ^{fw-minimised}:hidden';
PART.SNAP_OVERLAY.jit = 'fixed [inset:0] [z-index:9998] [pointer-events:none] [display:none]';
PART.SNAP_PREVIEW.jit = 'absolute [border:2px_dashed_var(--rui-accent)] rounded-[6px] bg-[var(--rui-accent-subtle)] [transition:all_.15s_cubic-bezier(0.4,0,0.2,1)]';
PART.ATTACH_GUIDE.jit = 'fixed [inset:0] [z-index:9998] [pointer-events:none] [display:none]';
PART.ATTACH_LINE.jit = 'absolute bg-[var(--rui-accent)] rounded-[1px]';