/**
 * @fileoverview FloatingWindow state persistence (localStorage).
 * @module module/FloatingWindow/state
 */

/**
 * Save window state to localStorage.
 * @param {string|null} key      — localStorage key (no-op if null)
 * @param {{ x: number, y: number }} pos
 * @param {{ w: number, h: number }} size
 * @param {string|null} snapZone
 * @param {object|null} freeRect
 */
export function saveState(key, pos, size, snapZone, freeRect) {
    if (!key) return;
    try {
        const state = {
            x: pos.x, y: pos.y,
            w: size.w, h: size.h,
            snap: snapZone || undefined,
            fr: freeRect || undefined,
        };
        localStorage.setItem(key, JSON.stringify(state));
    } catch { /* quota */ }
}

/**
 * Restore window state from localStorage.
 * @param {string|null} key — localStorage key
 * @returns {object|null} saved state or null
 */
export function restoreState(key) {
    if (!key) return null;
    try {
        const saved = JSON.parse(localStorage.getItem(key));
        if (!saved || typeof saved.x !== 'number') return null;
        return saved;
    } catch { return null; }
}
